class MyQueue {
    Stack<Integer> frontStack;
    Stack<Integer> rearStack;

    public MyQueue() {
        frontStack = new Stack<>();
        rearStack = new Stack<>();
    }

    public void push(int x) {
        rearStack.push(x);
    }

    public int pop() {
        if (frontStack.isEmpty()) {
            while (!rearStack.isEmpty()) {
                frontStack.push(rearStack.pop());
            }
        }
        return frontStack.pop();
    }

    public int peek() {
        if (frontStack.isEmpty()) {
            while (!rearStack.isEmpty()) {
                frontStack.push(rearStack.pop());
            }
        }
        return frontStack.peek();
    }

    public boolean empty() {
        return frontStack.isEmpty() && rearStack.isEmpty();
    }
}
